		tmpNoiseSlider.min = '0';
		tmpNoiseSlider.max = '100';
		tmpNoiseSlider.value = String(Math.round(tmpThemeProvider.getNoiseLevel() * 100));

		let tmpNoiseValue = document.createElement('span');
